<template>

	<view class="forget-pass">
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<!-- <view class="container" v-if="type == 1 || type == 2">
			<view class="actionbar">
				{{title}}
			</view>
		</view> -->



		<view class="header" v-if="type == 3">
			<text class="title">
				输入短信验证码
			</text>
			<view class="">
				验证当前手机号
			</view>
		</view>
		<view class="label" v-if="type == 1 || type == 2">
			<!-- 请输入手机号 -->
		</view>
		<view class="code-input" v-if="type == 1 || type == 2">
			<input type="text" style="width: 100%;" placeholder-style="color:#d8dbe3;" placeholder="请输入手机号"
				v-model="mobile" />
		</view>
		<view class="code-input">
			<input type="text" placeholder-style="color:#d8dbe3;" placeholder="请输入验证码" v-model="code" />
			<!-- <text class="codes">获取验证码</text> -->
			<view class="codes" :style="is_sendCode?'color:#c3c8d9;':'color:red;'" @click="sendCode()">

				<u-verification-code :seconds="seconds" ref="uCode" @start="codeStart" @end="codeEnd"
					@change="codeChange" start-text="获取验证码" change-text="X秒"></u-verification-code>
				<view class="">
					{{tips}}
				</view>
			</view>
		</view>

		<view class="btn submit" v-if="type == 1 || type == 2" @click="save">
			确定
		</view>
		<view class="btn submit" v-if="type == 3" @click="checkFrom">
			确定
		</view>
	</view>

</template>

<script>
	import slideCode from '@/components/slideCode.vue'

	export default {
		components: {
			slideCode
		},
		data() {
			return {
				list: [],
				title: '',
				mobile: '',
				type: '',
				code: '',

				type_code: '',
				user: {
					company: '',
					qq: '',
					email: '',
					password: '',
					trader_password: '',
				},
				tips: '',
				seconds: 60,
				is_sendCode: false, //是否发送验证码
				slideCode: [{
					show: false
				}],
				session_id: [], //会自动生成的
			}
		},
		onLoad(e) {
			this.type = e.type
			switch (e.type) {
				case '1':
					this.title = '绑定手机号'
					break;
				case '2':
					this.title = '修改手机号'
					break;
			}


			uni.setNavigationBarTitle({
				title: this.title
			})

			if (e.type_code) {
				this.type_code = e.type_code
			}
			this.$slideCode_init(0); //初始化图形滑块



		},
		methods: {
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值



				//发送验证码
				this.canGetCode()


			},
			codeChange(text) {
				this.tips = text;
			},

			//发送验证码
			sendCode() {

				if (this.type == 3) {
					if (!this.$u.test.mobile(this.userinfo.mobile)) return this.$util.msg('请输入正确的手机号')
				} else {
					if (!this.$u.test.mobile(this.mobile)) return this.$util.msg('请输入正确的手机号')
				}



				this.slideCode[0].show = true; //滑块验证码


			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			canGetCode() {
				if (this.$refs.uCode.canGetCode) {

					// 模拟向后端请求验证码
					uni.showLoading({
						title: '正在获取验证码'
					})

					let send_type = 14
					let mobile = this.mobile
					switch (this.type) {
						case '1':
						case '2':
							break;
						case '3':
							send_type = 15
							mobile = this.userinfo.mobile
							break;
					}


					let data = {
						send_type: send_type,
						mobile: mobile,
						session: this.session_id[0],
					}
					this.$u.api.sendCode(data).then(res => {


						uni.hideLoading();
						// 这里此提示会被this.start()方法中的提示覆盖
						this.$util.msg('验证码已发送');
						// 通知验证码组件内部开始倒计时
						this.$refs.uCode.start();
					}).catch((res) => {
						console.log(res);
						// this.$u.toast('验证码已发送');
					})



				} else {
					this.$u.toast('倒计时结束后再发送');
				}
			},
			loadData() {
				// this.$u.api.ucenterset({})
				// 	.then(res => {
				// 		this.list = res
				// 	}).catch(res => {})
			},
			checkFrom() {

				if (this.code == '') {
					this.$util.msg('请输入验证码')
					return false;
				}


				if (this.type == 3) {

					this.$u.api.valiCode({
							code: this.code,
							type: 15
						})
						.then(res => {

							this.$util.msg('验证成功')
							setTimeout(() => {
								this.$util.on('/pages/ucenter_sub/bind_mobile?type=2&type_code=' + this.code)

							}, 1500)



						}).catch(res => {})


				} else {
					if (!this.$u.test.mobile(this.mobile)) {
						this.$util.msg('请输入正确的手机号')
						return false;
					}

				}


				return true;
			},
			async save() {
				if (!this.checkFrom()) {
					return;
				}


				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				this.user.type = 'mobile'
				this.user.code = this.code
				this.user.mobile = this.mobile

				if (this.type == 2) {
					this.user.type_code = this.type_code

				}

				await this.$u.api.userinfosave(this.user)
					.then(res => {


						this.$u.vuex('userinfo.mobile', res.data);


						this.$util.msg('保存成功')

						if (this.type == 2) {
							setTimeout(() => {
								//注册成功前往首页
								this.$util.back(2);
							}, 1500)
						} else {
							setTimeout(() => {
								//注册成功前往首页
								this.$util.back();
							}, 1500)
						}

					}).catch(res => {})

				uni.hideLoading()
			}
		}
	}
</script>
<style scoped>
	page {
		background-color: #f5f7fa;
		word-wrap: break-word;
		line-height: 1.3;
		font-family: Regular, Droid Sans, Droid Sans Fallback, STHeiti, SimHei, Hei;
	}
</style>
